<script setup lang="ts">import{Head,Link,useForm}from'@inertiajs/vue3';import{ArrowLeft,Mail}from'@lucide/vue';import BrandLogo from '../../Components/BrandLogo.vue';defineProps<{status?:string}>();const form=useForm({email:''});</script>
<template><Head title="Reset password"/><main class="simple-auth-page"><section><BrandLogo/><Link href="/login" class="auth-back"><ArrowLeft/>Back to sign in</Link><h1>Reset your password</h1><p>Enter your account email and we’ll send you a secure, time-limited reset link.</p><div v-if="status" class="auth-success">{{status}}</div><form @submit.prevent="form.post('/password/email')"><label>Email address<span class="auth-input-icon"><Mail/><input v-model="form.email" class="su-input" type="email" required placeholder="name@example.com"/></span><small v-if="form.errors.email" class="error">{{form.errors.email}}</small></label><button class="su-btn su-btn-primary" :disabled="form.processing">{{form.processing?'Sending…':'Send reset link'}}</button></form></section></main></template>
